// ChatView.tsx — simplified for clarity
import { useState, useRef, useEffect } from "react";

interface ToolCall { id: string; name: string; input: unknown; result?: string; }
interface Message { id: string; role: "user"|"assistant"; text: string; toolCalls: ToolCall[]; }

export function ChatView({ sessionId }: { sessionId: string }) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [draft, setDraft] = useState("");
  const bottomRef = useRef<HTMLDivElement>(null);

  async function send() {
    const userMsg: Message = { id: crypto.randomUUID(), role: "user", text: draft, toolCalls: [] };
    const asstMsg: Message = { id: crypto.randomUUID(), role: "assistant", text: "", toolCalls: [] };
    setMessages(prev => [...prev, userMsg, asstMsg]);
    setDraft("");

    const res = await fetch(`/chat/${sessionId}/message`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ content: draft }),
    });

    const reader = res.body!.getReader();
    const decoder = new TextDecoder();
    let buf = "";

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buf += decoder.decode(value, { stream: true });
      const lines = buf.split("\n\n");
      buf = lines.pop() ?? "";

      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const evt = JSON.parse(line.slice(6));

        if (evt.type === "text") {
          setMessages(prev => prev.map(m =>
            m.id === asstMsg.id ? { ...m, text: m.text + evt.text } : m
          ));
        } else if (evt.type === "tool_start") {
          setMessages(prev => prev.map(m =>
            m.id === asstMsg.id
              ? { ...m, toolCalls: [...m.toolCalls, { id: evt.id, name: evt.name, input: {} }] }
              : m
          ));
        } else if (evt.type === "tool_result") {
          setMessages(prev => prev.map(m =>
            m.id === asstMsg.id
              ? { ...m, toolCalls: m.toolCalls.map(tc =>
                  tc.id === evt.id ? { ...tc, result: evt.result } : tc
                )}
              : m
          ));
        }
      }
      bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }

  return (
    <div className="flex flex-col h-full">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map(m => <MessageBubble key={m.id} message={m} />)}
        <div ref={bottomRef} />
      </div>
      <div className="p-4 border-t border-slate-700 flex gap-2">
        <textarea
          className="flex-1 bg-slate-800 rounded p-2 text-sm text-slate-100 resize-none"
          rows={2}
          value={draft}
          onChange={e => setDraft(e.target.value)}
          onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }}}
          placeholder="Ask a question…"
        />
        <button onClick={send} className="bg-indigo-600 text-white px-4 rounded text-sm">Send</button>
      </div>
    </div>
  );
}

// ToolCallPill.tsx
import { useState } from "react";

interface ToolCall { id: string; name: string; input: unknown; result?: string; }

export function ToolCallPill({ tc }: { tc: ToolCall }) {
  const [open, setOpen] = useState(false);
  const status = tc.result !== undefined ? "done" : "running";

  return (
    <div className="my-2 rounded-lg border border-green-900 bg-green-950 text-xs font-mono">
      <button
        onClick={() => setOpen(o => !o)}
        className="w-full flex items-center gap-2 px-3 py-1.5 text-left"
      >
        <span className="text-green-400">⚙</span>
        <span className="text-green-300 font-semibold">{tc.name}</span>
        <span className={`ml-auto px-1.5 py-0.5 rounded text-[10px] ${
          status === "done" ? "bg-green-800 text-green-200" : "bg-yellow-800 text-yellow-200"
        }`}>
          {status === "done" ? "done" : "running…"}
        </span>
        <span className="text-slate-500">{open ? "▲" : "▼"}</span>
      </button>

      {open && (
        <div className="border-t border-green-900 p-3 space-y-2">
          <div>
            <span className="text-slate-500">Input</span>
            <pre className="mt-1 bg-slate-900 rounded p-2 text-slate-300 overflow-x-auto">
              {JSON.stringify(tc.input, null, 2)}
            </pre>
          </div>
          {tc.result && (
            <div>
              <span className="text-slate-500">Result</span>
              <pre className="mt-1 bg-slate-900 rounded p-2 text-slate-300 overflow-x-auto max-h-40">
                {tc.result}
              </pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// TypingIndicator.tsx
export function TypingIndicator() {
  return (
    <div className="flex items-end gap-2">
      <div className="bg-slate-800 rounded-2xl rounded-bl-sm px-4 py-3">
        <div className="flex gap-1 items-center h-4">
          {[0, 1, 2].map(i => (
            <span
              key={i}
              className="w-2 h-2 rounded-full bg-indigo-400 animate-bounce"
              style={{ animationDelay: `${i * 150}ms` }}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

// EmptyState.tsx — shown when the session has no messages yet
export function EmptyState({ suggestions }: { suggestions: string[] }) {
  return (
    <div className="flex flex-col items-center justify-center h-full gap-6 text-slate-400">
      <div className="text-4xl">✦</div>
      <p className="text-lg font-medium text-slate-300">How can I help?</p>
      <div className="grid grid-cols-2 gap-2 max-w-lg w-full px-4">
        {suggestions.map(s => (
          <button
            key={s}
            className="text-left text-sm bg-slate-800 hover:bg-slate-700 rounded-lg p-3 text-slate-300"
          >
            {s}
          </button>
        ))}
      </div>
    </div>
  );
}

# Server: emit error events into the SSE stream
async def safe_stream(session_id: str, history: list):
    try:
        async with client.messages.stream(...) as stream:
            async for event in stream:
                yield event
    except anthropic.RateLimitError:
        yield {"type": "error", "code": "rate_limit",
               "message": "Rate limit reached. Please wait a moment and try again."}
    except anthropic.BadRequestError as e:
        if "prompt is too long" in str(e):
            yield {"type": "error", "code": "context_overflow",
                   "message": "Conversation is too long. Start a new session or summarise earlier messages."}
        else:
            raise
    except anthropic.APIStatusError as e:
        if e.status_code == 529:
            yield {"type": "error", "code": "overloaded",
                   "message": "Claude is currently overloaded. Retrying in 10 seconds…"}
            await asyncio.sleep(10)
            # re-enter the stream — simplified; real code would recurse with retry limit
        else:
            raise

// ErrorCard.tsx — renders inline in the message list
export function ErrorCard({ code, message, onRetry }: {
  code: string; message: string; onRetry?: () => void;
}) {
  return (
    <div className="flex items-start gap-3 bg-red-950 border border-red-800 rounded-xl p-4 text-sm">
      <span className="text-red-400 text-lg">⚠</span>
      <div className="flex-1">
        <p className="text-red-200">{message}</p>
        <p className="text-red-600 text-xs mt-1">{code}</p>
      </div>
      {onRetry && (
        <button onClick={onRetry} className="text-xs text-red-300 hover:text-red-100 underline">
          Retry
        </button>
      )}
    </div>
  );
}

function useAutoScroll(containerRef: React.RefObject<HTMLDivElement>, dependency: unknown) {
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    // Only scroll if within 120px of the bottom
    const nearBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 120;
    if (nearBottom) {
      el.scrollTop = el.scrollHeight;
    }
  }, [dependency]);
}

